// Parse le message Telegram
const msg = $input.first().json.message.text || '';
const parts = msg.trim().split(/\s+/);
const cmd = parts[0]?.replace('/', '').toLowerCase();

// Détecter le réseau
let network = 'twitter';
if (msg.toLowerCase().includes('linkedin') || msg.toLowerCase().includes(' li ')) {
  network = 'linkedin';
}

// Détecter le format
const formats = ['raw_build','hot_take','behind_scenes','ai_authority','storytelling','one_liner','axora_hype','engagement_bait'];
let format = '';
for (const f of formats) {
  if (msg.toLowerCase().includes(f.replace('_', ' ')) || msg.toLowerCase().includes(f)) {
    format = f;
    break;
  }
}
// Aliases
if (msg.toLowerCase().includes('hot take')) format = 'hot_take';
if (msg.toLowerCase().includes('one liner') || msg.toLowerCase().includes('oneliner')) format = 'one_liner';
if (msg.toLowerCase().includes('story')) format = 'storytelling';
if (msg.toLowerCase().includes('axora')) format = 'axora_hype';
if (msg.toLowerCase().includes('bts') || msg.toLowerCase().includes('behind')) format = 'behind_scenes';

// Construire le topic (tout sauf la commande et les keywords)
let topic = parts.slice(1).join(' ')
  .replace(/linkedin|twitter|li /gi, '')
  .replace(new RegExp(formats.join('|').replace(/_/g, '.'), 'gi'), '')
  .replace(/hot.take|one.liner|behind.the.scenes/gi, '')
  .trim();

// Map des commandes
const commandMap = {
  'today': 'today',
  'aujourd': 'today',
  'aujourdhui': 'today', 
  'tomorrow': 'tomorrow',
  'demain': 'tomorrow',
  'week': 'week',
  'semaine': 'week',
  'post': 'post',
  'formats': 'formats',
  'help': 'help',
  'start': 'help',
};

const command = commandMap[cmd] || (cmd === 'today' ? 'today' : 'help');

return {
  command,
  topic: topic || undefined,
  network,
  format: format || undefined,
  chat_id: $input.first().json.message.chat.id
};
